This can be solved by Kahn's topological sort algorithm + finding the critical path in a DAG
More on critical path here: https://en.wikipedia.org/wiki/Directed_acyclic_graph

```
from collections import defaultdict
from collections import deque
class Solution:
    def scheduled_tasks(self, numTasks, prerequisites, times):
        graph = defaultdict(list)
        indegree = [0]*numTasks
        new_times = [0]*numTasks
        res = []

        for src, dst in prerequisites:
            graph[src].append(dst)
            indegree[dst] += 1

        def kahn(n):
            q = deque()
            for i in range(n):
                if indegree[i] == 0:
                    new_times[i] = times[i]
                    q.append(i)

            while len(q):
                task = q.popleft()
                for adj in graph[task]:
                    new_times[adj] = max(new_times[adj], new_times[task] + times[adj])
                    indegree[adj] -= 1
                    if indegree[adj] == 0:
                        q.append(adj)

            return max(new_times)

        return kahn(numTasks)
obj = Solution()
num = 3
dependency = [[0, 1], [0, 2]]
times = [3, 5, 6]
print(obj.scheduled_tasks(num, dependency, times))
# result is 9
