public class MinimumTimeToCompleteTaskSnap {

    private static int dfs(int i, ArrayList<Boolean> visited, ArrayList<Integer> time, ArrayList<ArrayList<Integer>> edges) {
        visited.add(i, true);
        int val = time.get(i);
        if(i < edges.size() ) {
            for (int v : edges.get(i)) {
                if (!visited.get(v)) {
                    val += dfs(v, visited, time, edges);
                }
            }
        }
        return val;
    }

    public static int minTime(ArrayList<ArrayList<Integer>> pairs, ArrayList<Integer> time) {
        ArrayList<ArrayList<Integer>> edges = new ArrayList<>();
        ArrayList<Boolean> visited = new ArrayList<>();
        ArrayList<Integer> inbound = new ArrayList<>();
        int minTime = 0, n = time.size();
        for(int i = 0; i < n; ++i) {
            visited.add(false);
            inbound.add(0);
        }
        for(ArrayList<Integer> pair : pairs) {
            Integer u = pair.get(0), v = pair.get(1);
            if(edges.size() == 0 || edges.get(u) == null) {
                edges.add(u, new ArrayList<>());
            }
            edges.get(u).add(v);
            inbound.add(v, inbound.get(v) + 1);
        }

        for(int i = 0; i < n; ++i) {
            if (inbound.get(i) == 0) {
                minTime = Math.max(minTime, dfs(i, visited, time, edges));
            }
        }
        return minTime;
    }

